#!/usr/bin/env python# -*- coding:utf-8 -*-# @Time : 2024/6/10# @Author : cyq# @File : file# @Software: PyCharm# @Desc:from sqlalchemy import Column, String, ForeignKeyfrom sqlalchemy.dialects.mysql import INTEGERfrom app.model.basic import BaseModelclass FileModel(BaseModel):    __tablename__ = "file"    file_name = Column(String(50), comment="附件名称")    file_type = Column(String(100), comment="附件格式")    file_path = Column(String(250), comment="路径")    interface_uid = Column(String(50), ForeignKey("interface.uid", ondelete="CASCADE"), nullable=True)    # interface_uid = Column(String(50), nullable=True)  # 先不加外键    def __repr__(self):        return f"<{FileModel.__name__} {self.file_name}>"